import { useState } from 'react';
import { Link } from 'react-router-dom';


import Input from './components/reg-log-components/input';
import Checkbox from './components/reg-log-components/checkbox';
import Button from './components/reg-log-components/button';

const Login = ({ onLogin, changeOnRegisterPage }) => {

    const [username, setUsername] = useState('');
    const [password, setPassword] = useState('');

  return (
    <div>
      <div>
        <div>
          <header>Sign In</header>

          <Input
            icon="/images/icons/username.svg"
            alt="username"
            placeholder="Enter Username"
            value={username}
            onChange={(e) => setUsername(e.target.value)}
            className={auth.login_margin_left}
          />

          <Input
            icon="/images/icons/black_password.svg"
            alt="password"
            placeholder="Enter Password"
            type="password"
            value={password}
            onChange={(e) => setPassword(e.target.value)}
            className={auth.login_margin_left}
          />

          <div className={`horizontal left gap10 ${auth.login_margin_left}`}>
            <input type="checkbox" className="center" />
            <label className="nowrap center margin_top_1 light">Remember Me</label>
          </div>

          <Button text="Login" onClick={onLogin} className={auth.login_margin_left}/>

          <div className={`${auth.icon_line} ${auth.login_margin_left}`}>
            <label>Or, Login with</label>
            <img src="/images/icons/facebook.svg" alt="facebook" />
            <img src="/images/icons/google.svg" alt="google" />
            <img src="/images/icons/x.svg" alt="x" />
          </div>

          <div className={auth.login_margin_left}>
            <label>Don't have an account? </label>
            <label className="blue_text" onClick={changeOnRegisterPage}><Link to="/register">Create One</Link></label>
          </div>
        </div>

        <div className={auth.authentication_image_block}>
          <img src="/images/login.png" alt="login" className={auth.login_image} />
        </div>
      </div>
    </div>
  );
};

export default Login;
